#[derive(Debug)]
struct FieldError {
    field: &'static str,
    message: String,
}

fn validate_user(user: &CreateUser) -> Result<(), Vec<FieldError>> {
    let mut errors = Vec::new();
    if user.name.is_empty() {
        errors.push(FieldError { field: "name", message: "is required".into() });
    }
    if !user.email.contains('@') {
        errors.push(FieldError { field: "email", message: "invalid format".into() });
    }
    if user.age > 150 {
        errors.push(FieldError { field: "age", message: "must be <= 150".into() });
    }
    if errors.is_empty() { Ok(()) } else { Err(errors) }
}

