    Ok(Json(user).into_response())
}

// Log once in middleware:
async fn log_errors<B>(req: Request<B>, next: Next<B>) -> Response {
    let resp = next.run(req).await;
    if resp.status().is_server_error() {
        tracing::error!(status = %resp.status(), "server error");
    }
    resp
}

