use std::panic;

// At an FFI boundary:
#[no_mangle]
pub extern "C" fn ffi_process(data: *const u8, len: usize) -> i32 {
    let result = panic::catch_unwind(|| {
        let slice = unsafe { std::slice::from_raw_parts(data, len) };
        process(slice)
    });
    match result {
        Ok(Ok(())) => 0,
        Ok(Err(_)) => -1,
        Err(_panic) => -2, // caught panic
    }
}

